    h = max(model.S)
    if tau_x < h and (x, y) in model.A:
        expr_left = sum(sum(sum(model.f_d[x, tau_x - s1, y, tau_x + s2, d] for d in model.N) for s2 in pyo.RangeSet(1, h - tau_x, 1)) for s1 in pyo.RangeSet(0, tau_x, 1))
